<!DOCTYPE html><html><head><meta charset="UTF-8"><title>DepEd Lesson Planner</title><link rel="stylesheet" href="style.css"></head><body><div class="container"><h1>DepEd 2026 Appendix A Lesson Planner</h1><div class="no-print"><a href="create.php">Create New Lesson Plan</a><a href="search.php">Search</a><a href="calendar.php">Calendar View</a></div><h2>Saved Lesson Plans</h2><?php $result=$conn->query("SELECT * FROM lesson_plans ORDER BY lesson_date DESC, created_at DESC"); ?><table><tr><th>ID</th><th>Grade</th><th>Learning Area</th><th>Color</th><th>Term</th><th>Date</th><th>Name of Lesson</th><th>Actions</th></tr><?php while($row=$result->fetch_assoc()){ ?><tr><td><?php echo $row['id']; ?></td><td><?php echo htmlspecialchars($row['grade_level']); ?></td><td><?php echo htmlspecialchars($row['subject']); ?></td><td><span class="color-dot" style="background:<?php echo htmlspecialchars($row['subject_color']); ?>"></span></td><td><?php echo htmlspecialchars($row['term']); ?></td><td><?php echo htmlspecialchars($row['lesson_date']); ?></td><td><?php echo htmlspecialchars($row['topic']); ?></td><td><a href="view.php?id=<?php echo $row['id']; ?>">View</a><a href="edit.php?id=<?php echo $row['id']; ?>">Edit</a><a href="export_word.php?id=<?php echo $row['id']; ?>">Word</a><a href="export_excel.php?id=<?php echo $row['id']; ?>">Excel</a><a class="delete" href="delete.php?id=<?php echo $row['id']; ?>" onclick="return confirm('Delete this lesson plan?')">Delete</a></td></tr><?php } ?></table></div></body></html>
